    `size` STRING COMMENT 'Number of registered members or subscribers within this household. Used for family plan eligibility and simultaneous stream limit enforcement. | Column size (INT) in subscriber.household',
    `source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in subscriber.household',
    `state_province` STRING COMMENT 'State, province, or region code for the household address. Used for regulatory compliance and regional content licensing. | Column state_province (STRING) in subscriber.household',
    `subscription_end_date` DATE COMMENT 'Date when the households current subscription is scheduled to end or renew. Null for active auto-renewing subscriptions. | Column subscription_end_date (DATE) in subscriber.household',
    `subscription_start_date` DATE COMMENT 'Date when the households current paid subscription began. May differ from account creation date if there was a trial period or reactivation. | Column subscription_start_date (DATE) in subscriber.household',
    `time_zone` STRING COMMENT 'IANA time zone identifier for the household location. Used for scheduling, program guide display, and live event timing. | Column time_zone (STRING) in subscriber.household',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in subscriber.household',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this household record was last modified in the data platform. Used for change tracking and incremental processing. | Column updated_timestamp (TIMESTAMP) in subscriber.household',
    `verification_method` STRING COMMENT 'Method used to verify the households identity and location. Multiple methods may be used in combination for higher confidence. | Column verification_method (STRING) in subscriber.household. Valid values are `credit_card_avs|utility_bill|government_id|ip_geolocation|device_fingerprint|manual_review`',
    `verification_status` STRING COMMENT 'Status of household identity and address verification process. Used to enforce geographic entitlements and prevent fraudulent account creation. | Column verification_status (STRING) in subscriber.household. Valid values are `verified|pending|failed|not_required`',
    CONSTRAINT pk_household PRIMARY KEY(`household_id`)
) COMMENT 'Represents a logical household grouping of one or more subscribers sharing a service plan. Tracks household-level attributes including address, geographic market (DMA), household size, primary account holder reference, parental control settings, simultaneous stream limits, and household verification status. Supports MVPD household-based entitlement models, family plan billing, and account sharing enforcement. | Unity Catalog table: media_broadcasting_ecm.subscriber.household';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`subscriber`.`subscription_plan` (
